INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('12-clinic-system',2,12,'CLINIC SYSTEM','He thong phong kham',12,'draft','2026-06-20T10:47:06Z','2026-06-20T10:47:06Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3cd08f3b-f417-409d-9c6f-0ab7f48dd18c','12-clinic-system',NULL,2,'12.1 Clinic System là gì?','121-clinic-system-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b30c3121-3e99-462e-a956-49a4413e61a6','3cd08f3b-f417-409d-9c6f-0ab7f48dd18c',0,'text','Media Network có nhiệm vụ đưa phòng khám đến gần hơn với khách hàng. Nó tạo ra sự chú ý, cung cấp thông tin và bước đầu xây dựng niềm tin. Nhưng niềm tin đó chỉ thực sự được xác nhận khi khách hàng bước vào phòng khám và trải nghiệm toàn bộ quá trình điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57cc1088-dada-417c-8b23-e6ade38feb98','3cd08f3b-f417-409d-9c6f-0ab7f48dd18c',1,'text','Clinic System chính là nơi lời hứa thương hiệu được kiểm chứng bằng trải nghiệm thật . Nếu Media Network là nơi khách hàng biết đến bạn, thì Clinic System là nơi họ cảm nhận rõ nhất phòng khám có chuyên nghiệp hay không, bác sĩ có đáng tin hay không, quy trình có rõ ràng hay không, và trải nghiệm có đủ tốt để họ quay lại hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26b35c42-9443-456b-b7cf-476e015c49b0','3cd08f3b-f417-409d-9c6f-0ab7f48dd18c',2,'text','Nói đơn giản, Media Network mang khách hàng đến cửa, còn Clinic System quyết định họ có bước tiếp vào hành trình tin tưởng, điều trị, tái khám và giới thiệu hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a0b11062-c47a-48c7-b3f6-7f9d1661cc13','3cd08f3b-f417-409d-9c6f-0ab7f48dd18c',3,'text','Clinic System là hệ thống vận hành nội bộ của phòng khám gồm quy trình tiếp nhận, khám và chẩn đoán, tư vấn lập kế hoạch điều trị, thực hiện điều trị (chairside), kiểm soát chất lượng, chăm sóc sau điều trị và ghi nhận case/review; kèm dashboard KPI, SOP và vai trò nhân sự để đảm bảo vận hành ổn định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d33a3ba5-2533-44d6-b248-92c2c3f561c8','3cd08f3b-f417-409d-9c6f-0ab7f48dd18c',4,'image',NULL,'book/12-clinic-system/45f71d16-f317-4a57-850f-c511ae288d28-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1ccfdae1-5975-46e1-ab20-195271e2fdab','12-clinic-system',NULL,2,'12.2 Vai trò của Clinic System','122-vai-tro-cua-clinic-system',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4a08faef-b52b-460c-82fb-611c2fe46b8c','1ccfdae1-5975-46e1-ab20-195271e2fdab',5,'text','Clinic System là nơi **thương hiệu được kiểm chứng bằng trải nghiệm thật**.Marketing có thể tạo ra sự chú ý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e0cbf25-74f4-462e-8617-434c89853355','1ccfdae1-5975-46e1-ab20-195271e2fdab',6,'text','Personal Brand có thể tạo niềm tin ban đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36902a67-aa5a-4520-be2f-32f402779d1b','1ccfdae1-5975-46e1-ab20-195271e2fdab',7,'text','Content có thể kéo khách hàng đến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc44fe1b-2eab-42ed-8872-9fcffb988bf9','1ccfdae1-5975-46e1-ab20-195271e2fdab',8,'text','Nhưng **Clinic System** mới là nơi quyết định:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('30ab3bbc-5b17-486d-b913-fe767a11a4c0','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có tin tưởng phòng khám khôngNiềm tin trên mạng là niềm tin vay mượn. Niềm tin thực sự chỉ hình thành ở 30 giây đầu tiên khi khách hàng bước qua cánh cửa: không gian có sạch sẽ không, mùi hương có dễ chịu không, và ánh mắt của đội ngũ tiếp đón có thực sự chân thành và chuyên nghiệp?','benh-nhan-co-tin-tuong-phong-kham-khongniem-tin-tren-mang-la-niem-tin-vay-muon-n',2,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8ddd57b3-0135-4720-82aa-091451deb57b','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có đồng ý điều trị khôngLead đổ về từ CRM, Telesale chốt được lịch hẹn, nhưng chữ ký vào phác đồ điều trị lại phụ thuộc hoàn toàn vào năng lực thăm khám của Bác sĩ. Sự thấu cảm, cách giải thích vấn đề rành mạch và một lộ trình lâm sàng chuẩn xác là chìa khóa mở ra quyết định "xuống tiền".','benh-nhan-co-ong-y-ieu-tri-khonglead-o-ve-tu-crm-telesale-chot-uoc-lich-hen-nhun',3,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('181a130a-3484-4081-8bbb-a9811d85c568','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có hài lòng khôngHài lòng không chỉ là kết quả răng đẹp hay hết đau. Hài lòng là trải nghiệm không đau trong suốt quá trình tiêm tê, là bàn tay ân cần của trợ thủ khi thấm nước bọt, là việc không phải chờ đợi quá lâu so với lịch hẹn.','benh-nhan-co-hai-long-khonghai-long-khong-chi-la-ket-qua-rang-ep-hay-het-au-hai-',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7cf1ca26-67bb-4da6-91de-6a4ea12abcb5','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có quay lại khôngMột hệ thống Clinic chuẩn mực sẽ biến những dịch vụ một lần (như nhổ răng, trám răng) thành sự gắn bó cả đời (lấy cao răng định kỳ, thăm khám tổng quát hàng năm). Họ chỉ quay lại khi nơi đây mang lại cho họ cảm giác an toàn như ở nhà.','benh-nhan-co-quay-lai-khongmot-he-thong-clinic-chuan-muc-se-bien-nhung-dich-vu-m',5,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5b9403bc-6e9b-47d4-adda-a48b304e2ae2','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có để lại review khôngKhách hàng hiếm khi tự động khen ngợi trừ khi trải nghiệm đó vượt quá sự mong đợi của họ. Một quy trình lâm sàng mượt mà kết hợp với sự tận tâm tuyệt đối chính là chất xúc tác để họ sẵn sàng cầm điện thoại lên và đánh giá 5 sao bằng tất cả sự nhiệt tình.','benh-nhan-co-e-lai-review-khongkhach-hang-hiem-khi-tu-ong-khen-ngoi-tru-khi-trai',6,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('36eab4b2-c9de-4daf-9f0c-7df27e829d52','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Bệnh nhân có giới thiệu người quen khôngĐây là đỉnh cao của mọi hệ thống. Khi Clinic System hoạt động hoàn hảo, mỗi bệnh nhân bước ra khỏi phòng khám sẽ trở thành một đại sứ thương hiệu, tự động mang về những khách hàng mới với chi phí marketing bằng 0 (Referral).','benh-nhan-co-gioi-thieu-nguoi-quen-khongay-la-inh-cao-cua-moi-he-thong-khi-clini',7,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bcf8135e-bbd4-411b-8330-c6eec277619c','12-clinic-system','1ccfdae1-5975-46e1-ab20-195271e2fdab',3,'Tóm lại','tom-lai',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d92db21-0b15-4f57-8cc6-0d990b109383','bcf8135e-bbd4-411b-8330-c6eec277619c',9,'text','Đừng đổ tiền vào Cỗ máy Growth Engine nếu chiếc thùng Clinic System của bạn đang thủng đáy. Việc kéo hàng trăm khách hàng đến một phòng khám có chất lượng dịch vụ tồi, quy trình lỏng lẻo và nhân sự thiếu năng lực chỉ là cách nhanh nhất để khuếch đại sự thất bại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3495df68-1211-4354-afd4-1226c08a2eb2','bcf8135e-bbd4-411b-8330-c6eec277619c',10,'text','Hãy nhớ rằng: **Marketing mang khách hàng đến, nhưng chỉ có Clinic System mới giữ chân được họ và biến họ thành tài sản vô giá của phòng khám.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c2a2fec0-7ac1-45e2-93fd-53b5b9552465','12-clinic-system',NULL,2,'12.3 Cấu trúc cốt lõi của Clinic System','123-cau-truc-cot-loi-cua-clinic-system',9,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0069bdd0-20a0-416c-84e5-caa39c621a30','12-clinic-system','c2a2fec0-7ac1-45e2-93fd-53b5b9552465',3,'Tư vấn &amp; điều trị - "Linh hồn" của hệ thống lâm sàng (Clinic system)Nếu các quy trình tự động hóa hay hệ thống CRM là bộ khung xương vững chắc, thì Tư vấn và Điều trị chính là linh hồn của toàn bộ Clinic System. Đây là hai điểm chạm quyết định sự thành bại của phòng khám RHM, nơi mọi lời hứa truyền thông phải được chứng minh bằng năng lực thực chiến.Để xây dựng một phòng khám bài bản, chúng ta không thể phó mặc hai khâu này cho cảm xúc hay "duyên" bán hàng. Mọi thứ phải được chuẩn hóa thành những bộ khung năng lực rõ ràng cho từng vị trí.','tu-van-amp-ieu-tri-linh-hon-cua-he-thong-lam-sang-clinic-systemneu-cac-quy-trinh',10,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b14bfb58-6b80-49c7-8872-f520bf34bc79','12-clinic-system','0069bdd0-20a0-416c-84e5-caa39c621a30',4,'Tư vấn: nghệ thuật chuyển đổi bằng sự thấu cảm và chuyên mônMột sai lầm rất phổ biến là đánh đồng Tư vấn với Bán hàng (Sales). Mục tiêu tối thượng của một ca tư vấn nha khoa không phải là "ép" khách mua dịch vụ bằng mọi giá. Tư vấn là quá trình gỡ rối tâm lý, chuyển đổi một người đang mơ hồ quan tâm thành một bệnh nhân có nhu cầu rõ ràng và khao khát được chữa trị.','tu-van-nghe-thuat-chuyen-oi-bang-su-thau-cam-va-chuyen-monmot-sai-lam-rat-pho-bi',11,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('916791b2-2824-40c3-bebe-3ac7f5b7a432','12-clinic-system','b14bfb58-6b80-49c7-8872-f520bf34bc79',5,'Một chuyên viên tư vấn hay một bác sĩ khi ngồi đối diện bệnh nhân phải làm chủ được cuộc hội thoại để giúp họ tự nhận ra 5 vấn đề cốt lõi:','mot-chuyen-vien-tu-van-hay-mot-bac-si-khi-ngoi-oi-dien-benh-nhan-phai-lam-chu-uo',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad61cafd-1e67-4208-b8c7-1c25237bc428','916791b2-2824-40c3-bebe-3ac7f5b7a432',11,'text','- Vấn đề răng miệng hiện tại thực chất là gì?- Nếu tiếp tục trì hoãn không xử lý, hậu quả sẽ tồi tệ ra sao?- Có những phương án y khoa nào để can thiệp?- Đâu là phác đồ tối ưu và phù hợp nhất với tài chính, tình trạng của riêng họ?- Vì sao họ nên đặt trọn niềm tin và sức khỏe vào phòng khám của chúng ta chứ không phải nơi khác?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c4a4c8d-04fe-4922-8b3b-4991872b46a8','12-clinic-system','b14bfb58-6b80-49c7-8872-f520bf34bc79',5,'Các Nấc Thang Của Một Quy Trình Tư Vấn Chuẩn:','cac-nac-thang-cua-mot-quy-trinh-tu-van-chuan',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9fd46b74-3304-4caf-a3c1-523ac315e65a','7c4a4c8d-04fe-4922-8b3b-4991872b46a8',12,'text','Để làm được điều đó, bộ khung nhiệm vụ của người tư vấn phải đi qua các bước cực kỳ chặt chẽ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('32f22ab4-db85-4171-aeb5-0242fde14382','7c4a4c8d-04fe-4922-8b3b-4991872b46a8',13,'text','- **Tiếp nhận:** Ghi nhận chính xác nhu cầu ban đầu, nguồn khách đến từ đâu và vấn đề cấp bách nhất họ đang gặp phải.- **Khai thác:** Tuyệt đối không vội vàng phán bệnh. Phải hỏi kỹ về triệu chứng, mong muốn sâu xa, những nỗi lo thầm kín (sợ đau, sợ mài răng) và giới hạn ngân sách.- **Giải thích:** Trực quan hóa tình trạng bằng phim X-quang, hình ảnh thực tế trong miệng và so sánh với các Case lâm sàng tương tự đã thành công.- **Đề xuất:** Đưa ra phương án điều trị mang tính cá nhân hóa, phân tích rõ thiệt hơn của từng lựa chọn.- **Chốt kế hoạch:** Đi đến cái bắt tay thống nhất về thời gian, chi phí, lộ trình thanh toán và các bước thực hiện tiếp theo.- **Cập nhật CRM:** Mọi thông tin (từ ngân sách, nỗi lo, đến lịch hẹn) phải được lưu trữ ngay lập tức vào hệ thống để bộ phận khác theo dõi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff2d8f5f-b737-4ec2-a5c2-210848546ce2','12-clinic-system','b14bfb58-6b80-49c7-8872-f520bf34bc79',5,'5 Tiêu Chí Vàng Của Một Buổi Tư Vấn Thành Công:','5-tieu-chi-vang-cua-mot-buoi-tu-van-thanh-cong',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d6792d56-67ce-4545-902e-5da5f7c7b8d8','ff2d8f5f-b737-4ec2-a5c2-210848546ce2',14,'text','- Bệnh nhân thấu hiểu tường tận tình trạng của chính mình.- Bệnh nhân cảm thấy được lắng nghe và tôn trọng.- Bệnh nhân hoàn toàn tin tưởng vào năng lực chuyên môn của Bác sĩ.- Bệnh nhân nhận thức rõ giá trị (chứ không chỉ nhìn vào giá cả) của phương án điều trị.- Bệnh nhân nắm rõ chính xác bước tiếp theo mình cần làm là gì.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d5890c8b-d8f2-4a1e-b79e-30e77cb8f092','12-clinic-system','0069bdd0-20a0-416c-84e5-caa39c621a30',4,'Điều trị: "sự thật trên ghế nha" và năng lực cốt lõi','ieu-tri-su-that-tren-ghe-nha-va-nang-luc-cot-loi',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54bc3170-f83a-40ea-a3e1-acd3b36ee70d','d5890c8b-d8f2-4a1e-b79e-30e77cb8f092',15,'text','Khi bệnh nhân đã gật đầu đồng ý, bước lên ghế nha và há miệng ra, đó là lúc phòng khám bước vào vùng "Sự thật tuyệt đối". **Điều trị** chính là trung tâm chuyên môn của toàn bộ Clinic System.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d67065a4-5b33-4119-ba80-2cec98790ee0','d5890c8b-d8f2-4a1e-b79e-30e77cb8f092',16,'text','Dù hệ thống Marketing có tốt đến đâu, nếu kết quả điều trị tồi, phòng khám cũng sẽ sụp đổ. Đây là nơi năng lực thực sự được phô diễn không qua lăng kính chỉnh sửa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8ad457f-86fa-483a-a38e-dbff9b01a997','12-clinic-system','0069bdd0-20a0-416c-84e5-caa39c621a30',4,'Một hệ thống điều trị đẳng cấp sẽ chinh phục bệnh nhân thông qua 6 yếu tố:','mot-he-thong-ieu-tri-ang-cap-se-chinh-phuc-benh-nhan-thong-qua-6-yeu-to',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35fbc703-e44b-4c59-9417-537377c83771','e8ad457f-86fa-483a-a38e-dbff9b01a997',17,'text','- **Tay nghề bác sĩ:** Sự dứt khoát, chính xác và nhẹ nhàng trong từng thao tác. Bác sĩ giỏi không chỉ chữa khỏi bệnh, mà còn chữa bệnh một cách êm ái nhất.- **Quy trình điều trị:** Mọi bước lâm sàng phải được tuân thủ nghiêm ngặt theo phác đồ chuẩn y khoa, không được phép đốt cháy giai đoạn.- **Thiết bị hỗ trợ:** Máy móc công nghệ cao (máy quét dấu hàm 3D, máy Piezotome, laser...) không chỉ hỗ trợ bác sĩ mà còn giảm thiểu tối đa tổn thương cho bệnh nhân.- **Kiểm soát vô khuẩn:** Đây là lằn ranh sinh tử. Việc chuẩn hóa các checklist hàng ngày cho đội ngũ trợ thủ từ việc đóng gói dụng cụ, hấp sấy, dọn dẹp ghế nha sau mỗi ca—là bắt buộc để đảm bảo an toàn tuyệt đối, chống lây nhiễm chéo.- **Giao tiếp trong quá trình điều trị:** Bệnh nhân nằm trên ghế nha thường rất căng thẳng và sợ hãi. Một lời động viên: *"Anh làm rất tốt, mình sắp xong rồi nhé"*, hay sự thông báo trước: *"Bước này sẽ hơi ê một chút, chị chịu khó xíu nha"* sẽ xóa tan sự áp lực, biến việc chữa răng thành một trải nghiệm nhẹ nhàng, giúp họ thực sự cảm thấy *thích làm răng* hơn là sợ hãi.- **Kết quả sau điều trị:** Nụ cười mới, chức năng ăn nhai được phục hồi và sự bền vững theo thời gian là minh chứng đanh thép nhất cho mọi lời hứa thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('953019d4-9a63-4df9-baba-607f1b67e2c5','e8ad457f-86fa-483a-a38e-dbff9b01a997',18,'text','Khi bạn xây dựng được một khung năng lực đồng đều cho đội ngũ Tư vấn và thiết lập được sự kỷ luật thép trong khu vực Điều trị, Clinic System của bạn sẽ tự động sản sinh ra sự hài lòng. Và chính sự hài lòng đó sẽ kích hoạt lại bánh răng lan tỏa của Growth Engine, mang về những nguồn doanh thu mới một cách bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6b811638-9be8-4b52-a8b5-b34abf0fa20e','12-clinic-system','0069bdd0-20a0-416c-84e5-caa39c621a30',4,'Các bước điều trị chuẩn','cac-buoc-ieu-tri-chuan',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7cb4260c-40f9-4743-a0a3-17192be6c528','6b811638-9be8-4b52-a8b5-b34abf0fa20e',19,'image',NULL,'book/12-clinic-system/e0ca4fd0-4d79-4e79-93b3-bbfb2f0d2b61-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('38d65eca-fac5-48ad-b6f3-a3a385a21233','12-clinic-system','0069bdd0-20a0-416c-84e5-caa39c621a30',4,'Chuẩn điều trị đề xuất','chuan-ieu-tri-e-xuat',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51839cb3-a589-4c68-bd42-80954366df72','38d65eca-fac5-48ad-b6f3-a3a385a21233',20,'text','Điều trị không chỉ là làm đúng kỹ thuật.
Điều trị còn phải tạo được **niềm tin và cảm giác an tâm**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9bdd297-e93f-477d-8819-1ca8fe54162a','38d65eca-fac5-48ad-b6f3-a3a385a21233',21,'image',NULL,'book/12-clinic-system/c7d8501d-e0b5-47dc-bb30-8ec8426c127a-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1a6cba19-07bc-4141-9e5b-4ff4f0b2e970','12-clinic-system','c2a2fec0-7ac1-45e2-93fd-53b5b9552465',3,'CSKH (chăm sóc khách hàng) - Vũ khí bí mật tối ưu chi phí và lưu giữ trải nghiệmTrong hành trình quản lý và vận hành phòng khám, tôi thường chứng kiến một vòng lặp vắt kiệt sức lực của rất nhiều cơ sở: Đốt tiền quảng cáo tìm khách mới → Khám và điều trị → Bệnh nhân ra về và biến mất → Lại tiếp tục đốt tiền quảng cáo tìm khách mới.Để thoát khỏi chiếc bẫy tài chính này, phòng khám cần một chốt chặn cuối cùng nhưng lại mang sức mạnh lan tỏa lớn nhất: Hệ thống Chăm sóc khách hàng (CSKH).Nhiều người lầm tưởng CSKH chỉ đơn giản là gọi điện hỏi thăm "Anh/chị về nhà có đau không?". Không, một hệ thống CSKH chuẩn chỉnh là một chuỗi hành động có tính chiến lược, nhằm duy trì mối quan hệ khăng khít với bệnh nhân trong cả 3 giai đoạn: Trước, Trong và Sau điều trị.Khi bạn giữ chân được bệnh nhân cũ và đồng hành cùng họ đi đến cuối phác đồ, áp lực phải liên tục đổ tiền vào phễu Marketing sẽ giảm đi đáng kể. CSKH, vì thế, chính là vũ khí bí mật để tối ưu hóa chi phí vận hành.','cskh-cham-soc-khach-hang-vu-khi-bi-mat-toi-uu-chi-phi-va-luu-giu-trai-nghiemtron',19,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ad878bd5-fea6-4ad9-98f5-a287ec5365c6','12-clinic-system','1a6cba19-07bc-4141-9e5b-4ff4f0b2e970',4,'Bản đồ tác động','ban-o-tac-ong',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b460127-afbd-4a19-8418-4cb642d6c561','ad878bd5-fea6-4ad9-98f5-a287ec5365c6',22,'text','Một hệ thống CSKH bài bản không hoạt động dựa trên cảm tính. Mọi điểm chạm, mọi lời hỏi thăm đều trực tiếp can thiệp và cải thiện các chỉ số sinh tử trong vận hành phòng khám:**Cứu vãn "Ghế trống" – Tối ưu Tỷ lệ đến lịch hẹn ****(Show-up Rate)**Trong nha khoa, chi phí vận hành cho một giờ ghế trống (bao gồm mặt bằng, lương bác sĩ, khấu hao máy móc) là rất lớn. Một kịch bản CSKH xuất sắc trước điều trị (nhắc lịch qua Zalo, gọi điện xác nhận trước 24h, hướng dẫn đường đi và chỗ để xe) sẽ triệt tiêu tình trạng khách hàng "bùng" hẹn do quên hoặc e ngại. CSKH giúp bảo vệ quỹ thời gian vàng ngọc của bác sĩ và tối đa hóa công suất hoạt động của ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05dda9c8-469c-4648-8a16-5d05c2999996','ad878bd5-fea6-4ad9-98f5-a287ec5365c6',23,'text','Với những dịch vụ chỉ làm một lần như trám răng hay cạo vôi, tỷ lệ hoàn tất luôn là 100%. Nhưng với các ca phức tạp, kéo dài từ vài tháng đến vài năm như Niềng răng, Cấy ghép Implant hay Phục hình sứ toàn hàm, bệnh nhân rất dễ nản chí, mệt mỏi hoặc bỏ dở giữa chừng. Lúc này, CSKH đóng vai trò là "người đồng hành". Những tin nhắn nhắc nhở lịch siết răng, những cuộc gọi động viên sau khi cắm chốt Implant không chỉ thể hiện sự quan tâm mà còn là kỷ luật khéo léo, giữ cho bệnh nhân đi đúng lộ trình lâm sàng cho đến khi kết quả hoàn hảo nhất được tạo ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd4ed2a3-e54d-40e2-8dc9-826d1a8e3a04','ad878bd5-fea6-4ad9-98f5-a287ec5365c6',24,'text','Cảm xúc con người có tính thời điểm. Bệnh nhân sẽ cảm thấy hạnh phúc nhất, trút bỏ được gánh nặng lớn nhất ngay khoảnh khắc tháo niềng hoặc lắp xong chiếc răng sứ cuối cùng. Hệ thống CSKH phải "bắt" đúng điểm rơi tâm lý này để kích hoạt các kịch bản xin đánh giá. Một lời đề nghị tinh tế ngay tại phòng khám hoặc một tin nhắn chứa link Google Maps sau khi về nhà sẽ biến sự hài lòng vô hình thành những lời khen ngợi hữu hình (Social Proof). Đây là tài sản thương hiệu tồn tại mãi mãi trên môi trường số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe7089ce-0e24-4101-a082-4e894e672d08','ad878bd5-fea6-4ad9-98f5-a287ec5365c6',25,'text','Khách hàng cũ tin tưởng bạn, họ sẽ quay lại lấy cao răng, nhổ răng khôn hoặc làm thêm các dịch vụ khác. Nhưng sức mạnh khủng khiếp nhất của CSKH nằm ở **Referral (Sự giới thiệu truyền miệng)**. Khi được chăm sóc vượt mức kỳ vọng, bệnh nhân sẽ tự hào kể về trải nghiệm của họ với người thân, bạn bè. Họ vô tình trở thành những đại sứ thương hiệu nhiệt thành nhất cho phòng khám. Dòng khách hàng giới thiệu này có tỷ lệ chốt cực kỳ cao (vì niềm tin đã được bảo chứng từ người quen) và đặc biệt, chi phí thu mua khách hàng (CAC) hoàn toàn bằng 0.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34313735-b123-4ac2-a98f-4896ed611b67','ad878bd5-fea6-4ad9-98f5-a287ec5365c6',26,'text','**Tóm lại:** Nếu Bác sĩ là người tạo ra kết quả điều trị, thì CSKH là người đóng gói kết quả đó thành một trải nghiệm hoàn hảo. Một phòng khám sở hữu hệ thống CSKH mạnh mẽ sẽ không bao giờ thiếu vắng nụ cười của khách hàng và sự ổn định của dòng tiền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('716aae3b-5ab0-4b4b-b520-5c6781e561ec','12-clinic-system','1a6cba19-07bc-4141-9e5b-4ff4f0b2e970',4,'Ma trận Quy trình CSKH theo Hành trình Bệnh nhân','ma-tran-quy-trinh-cskh-theo-hanh-trinh-benh-nhan',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6b2a7b57-6476-4de5-ba02-5fd15627a4df','716aae3b-5ab0-4b4b-b520-5c6781e561ec',27,'text','Để nhân viên không bị sót việc, toàn bộ hoạt động CSKH được chia thành 5 giai đoạn với mục tiêu và hành động cốt lõi rõ ràng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c216d36-a2b4-46ab-a029-4dd651264f9f','716aae3b-5ab0-4b4b-b520-5c6781e561ec',28,'image',NULL,'book/12-clinic-system/7b7c2599-b323-4ed9-8219-dd48d7ec68e1-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff15cdf2-4211-4c19-9d47-7be6e9105d43','12-clinic-system','1a6cba19-07bc-4141-9e5b-4ff4f0b2e970',4,'Kịch bản CSKH Chuẩn hóa (Script mẫu cho nhân sự)','kich-ban-cskh-chuan-hoa-script-mau-cho-nhan-su',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea1a72d4-f6ff-4db4-956d-5dbde0122aa5','ff15cdf2-4211-4c19-9d47-7be6e9105d43',29,'text','Thay vì để nhân viên tự phát hỏi những câu sáo rỗng như *"Anh/chị có đau không?"* (dễ làm bệnh nhân tập trung vào cảm giác tiêu cực), hãy áp dụng bộ kịch bản tinh tế và chủ động dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9f2842f-1237-4329-8059-3316b758effa','ff15cdf2-4211-4c19-9d47-7be6e9105d43',30,'text','*Kịch bản nhắn tin Zalo (Sau khi nhổ răng khôn / tiểu phẫu / làm phôi implant 4-6 tiếng):*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16764507-382c-4089-8d94-b18f8fb287f1','ff15cdf2-4211-4c19-9d47-7be6e9105d43',31,'text','"Dạ em chào anh/chị [Tên_Bệnh_Nhân], em là [Tên_CSKH] từ phòng khám nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9968f5d-50f1-47f8-bfff-e2b4f4271713','ff15cdf2-4211-4c19-9d47-7be6e9105d43',32,'text','Hôm nay anh/chị cảm thấy thế nào sau khi thuốc tê tan hết rồi ạ? Ở vị trí răng vừa làm có bị sưng nhiều hay còn rỉ máu không anh/chị?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b5ba072-9ede-4be8-8008-d560793f1052','ff15cdf2-4211-4c19-9d47-7be6e9105d43',33,'text','Anh/chị lưu ý giúp em uống liều thuốc đầu tiên sau khi ăn nhẹ nhé. Em gửi lại hình ảnh hướng dẫn chế độ ăn uống và vệ sinh răng miệng trong 3 ngày đầu qua Zalo này để mình tiện theo dõi ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d4fc011-8b10-4af3-a084-ae17a6ba8ef2','ff15cdf2-4211-4c19-9d47-7be6e9105d43',34,'text','Nếu có bất kỳ dấu hiệu nào thấy không an tâm, anh/chị cứ chụp ảnh hoặc nhắn ngay cho em ở đây, các bác sĩ sẽ hỗ trợ mình liền nhé ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd192302-1084-4cbb-a292-cc0d5d6f95ec','ff15cdf2-4211-4c19-9d47-7be6e9105d43',35,'text','*Kịch bản gọi điện / nhắn tin xin Review Google Map (Sau khi hoàn tất điều trị 3-5 ngày):*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec2dc4f3-7995-4572-a7cd-667259b1da03','ff15cdf2-4211-4c19-9d47-7be6e9105d43',36,'text','"Dạ em chào anh [Vinh], nụ cười mới của mình tuần này ăn nhai và sinh hoạt hoàn toàn bình thường rồi đúng không anh? Đội ngũ bác sĩ bên em rất vui vì đã đồng hành cùng anh để có kết quả ưng ý như vậy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a64407bd-582e-48e3-b49f-388e3153946c','ff15cdf2-4211-4c19-9d47-7be6e9105d43',37,'text','Để giúp phòng khám ngày càng hoàn thiện dịch vụ và có thêm động lực cho các bác sĩ, anh [Vinh] có thể dành ra 1 phút tặng phòng khám một đánh giá 5 sao trên Google Map được không ạ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06b4adb0-f5b7-4f0d-932e-5abc91a6b852','ff15cdf2-4211-4c19-9d47-7be6e9105d43',38,'text','Anh bấm vào link này giúp em nhé: `[Link Google Map]`. Nha khoa xin gửi tặng anh một voucher chăm sóc răng miệng trị giá `[X]` cho lần tới như một lời cảm ơn chân thành ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1e0d2a69-4964-459a-9d6b-0f53ec5c1702','12-clinic-system','1a6cba19-07bc-4141-9e5b-4ff4f0b2e970',4,'Nguyên tắc cốt lõi của CSKH Nha khoa','nguyen-tac-cot-loi-cua-cskh-nha-khoa',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8090b999-70cb-4d94-b125-06b5fed6ce84','1e0d2a69-4964-459a-9d6b-0f53ec5c1702',39,'text','Luôn đi trước bệnh nhân một bước. Đừng đợi bệnh nhân đau rồi gọi điện hỏi, hãy chủ động liên hệ trước khi họ kịp cảm thấy lo lắng. Chăm sóc tận tâm ở giai đoạn "Sau điều trị" chính là chiếc chìa khóa vàng để mở ra giai đoạn "Dài hạn" và "Referral".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1491afc7-bcfe-4cca-957a-1287b57e7a13','12-clinic-system',NULL,2,'Tái khám - Trục xương sống tài chính và vòng lặp tăng trưởng bền vững','tai-kham-truc-xuong-song-tai-chinh-va-vong-lap-tang-truong-ben-vung',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('acc49238-16b9-4b9d-b00a-4151fdc24afb','1491afc7-bcfe-4cca-957a-1287b57e7a13',40,'text','Trong bức tranh toàn cảnh của hệ thống vận hành phòng khám RHM, chúng ta thường dành quá nhiều sự chú ý cho việc săn lùng khách hàng mới. Tuy nhiên, nếu Growth Engine là một cỗ máy tuần hoàn, thì **Tái khám** chính là bánh răng cuối cùng để khép kín vòng lặp đó và tạo ra nguồn lực dồi dào nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0196bcd-6709-471e-8c05-6ecf9ec1c791','1491afc7-bcfe-4cca-957a-1287b57e7a13',41,'text','Tái khám không đơn thuần là một thủ tục y tế khô khan. Đây là trục xương sống quyết định sự vững mạnh tài chính của phòng khám. Nếu như việc tìm kiếm một khách hàng mới (New Patient) tiêu tốn một khoản chi phí thu mua (CAC) khổng lồ thông qua quảng cáo, thì nhóm khách hàng tái khám lại mang về nguồn doanh thu có biên lợi nhuận cao nhất. Hơn thế nữa, họ chính là cái nôi để sản sinh ra hàng loạt các ca Referral (giới thiệu truyền miệng) chất lượng cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ffa3c73-94ee-4577-88d7-9e2226d247d1','1491afc7-bcfe-4cca-957a-1287b57e7a13',42,'text','Mục tiêu tối thượng của chúng ta là xóa bỏ cảm giác "phải đi khám răng", thay vào đó, kiến tạo một văn hóa để bệnh nhân thực sự **thích làm răng**, xem việc trở lại phòng khám nhẹ nhàng và thư giãn như một thói quen chăm sóc bản thân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('41a5c4bf-1578-4bd4-9b50-21b64a8a3cdd','12-clinic-system','1491afc7-bcfe-4cca-957a-1287b57e7a13',4,'Bản đồ phân loại tái khám và mục tiêu','ban-o-phan-loai-tai-kham-va-muc-tieu',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac79b9b0-e84b-491d-be85-34944026779e','41a5c4bf-1578-4bd4-9b50-21b64a8a3cdd',43,'image',NULL,'book/12-clinic-system/b8ce5668-d860-475f-90cd-3aa1b7699eb5-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0de8f88d-8044-434a-8dbe-8749a2cb29fa','12-clinic-system','1491afc7-bcfe-4cca-957a-1287b57e7a13',4,'Quy trình 5 Bước Chuẩn hóa Lịch Tái khám (Hồ sơ Bệnh nhân)','quy-trinh-5-buoc-chuan-hoa-lich-tai-kham-ho-so-benh-nhan',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75027f8e-f0a0-4a39-b626-8e1c1eb25a41','0de8f88d-8044-434a-8dbe-8749a2cb29fa',44,'text','Để không bỏ sót bất kỳ bệnh nhân nào, mỗi khi một ca điều trị kết thúc (hoặc một buổi hẹn hoàn thành), nhân viên phụ trách bắt buộc phải cập nhật đủ 6 trường thông tin sau vào hệ thống CRM',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e7e6800-48ed-4a9c-a333-342c7c6bea98','0de8f88d-8044-434a-8dbe-8749a2cb29fa',45,'text','[Mã Bệnh Nhân] → [Lịch Tái Khám Cụ Thể] → [Nhân Sự Phụ Trách] → [Kịch Bản Nhắc] → [Nhật Ký Xử Lý] → [Kết Quả & Cơ Hội]',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('afd744bd-95dd-4ac7-b072-00e0d2273239','0de8f88d-8044-434a-8dbe-8749a2cb29fa',46,'image',NULL,'book/12-clinic-system/f592b229-96b3-46a6-985e-647f2d9d66cb-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fe5888c-4205-47ca-948c-1f4e5901f121','0de8f88d-8044-434a-8dbe-8749a2cb29fa',47,'text','- **Lịch tái khám cụ thể:** Ngày giờ chính xác (không hẹn chung chung kiểu "tháng sau qua anh nhé").- **Người phụ trách:** Phân định rõ là Trợ thủ ca đó hay nhân viên Lễ tân/CSKH chịu trách nhiệm gọi/nhắn.- **Nội dung/Kịch bản nhắc:** Ghi rõ lý do tái khám (ví dụ: *Tái khám cắt chỉ Implant răng 36*).- **Trạng thái & Ghi chú kết quả:** Đến đúng hẹn / Trễ hẹn / Hủy lịch (Lý do hủy) / Đã đổi lịch sang ngày khác.- **Cơ hội Upsell/Cross-sell:** Bác sĩ ghi chú sẵn',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d70ccf89-46f4-424f-9b7e-daecaf6def5f','12-clinic-system','1491afc7-bcfe-4cca-957a-1287b57e7a13',4,'Bộ chỉ số đo lường hiệu suất tái khám(RECALL KPIs)','bo-chi-so-o-luong-hieu-suat-tai-khamrecall-kpis',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0179b4cf-e1f8-4fd1-8645-0ad60eba272a','d70ccf89-46f4-424f-9b7e-daecaf6def5f',48,'text','Mọi khung năng lực và quy trình quản trị đều trở nên vô nghĩa nếu thiếu đi các con số đo lường. Hệ thống tái khám phải được giám sát chặt chẽ qua các KPI:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d07c082-bfef-4472-82b5-e50e6a37303a','d70ccf89-46f4-424f-9b7e-daecaf6def5f',49,'text','- **Recall Rate (Tỷ lệ quay lại):** Bao nhiêu % khách hàng cũ của 6 tháng trước đã quay lại phòng khám trong tháng này? Chỉ số này phản ánh trực tiếp chất lượng lâm sàng của Clinic System.- **No-show Rate (Tỷ lệ bùng lịch tái khám):** Đánh giá hiệu quả của kịch bản nhắc lịch và thái độ của đội ngũ CSKH.- **Cross-sell Revenue (Doanh thu bán chéo):** Số tiền thu được từ các dịch vụ phát sinh khi khách hàng đến tái khám định kỳ.- **Referral Conversion Rate (Tỷ lệ chuyển đổi từ khách giới thiệu):** Bao nhiêu khách hàng tái khám đã thực sự mang đến một khách hàng mới?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('499d371d-5825-4a63-979f-106d74bab576','d70ccf89-46f4-424f-9b7e-daecaf6def5f',50,'text','Khi hoạt động tái khám được hệ thống hóa, nó không còn là những cuộc gọi vớt vát ngẫu nhiên. Nó trở thành một cỗ máy in tiền thứ hai, âm thầm nhưng vô cùng mạnh mẽ, nuôi dưỡng toàn bộ Growth Engine của phòng khám phát triển bền vững qua năm tháng.',NULL,NULL,NULL,NULL,NULL);
